    10	/// <summary>Posts immutable sales fulfillments and their issue ledger entries in one transaction.</summary>
    11	public sealed class EfSalesFulfillmentService(ApplicationDbContext dbContext) : ISalesFulfillmentService
    12	{
    13	    public async Task<SalesFulfillment?> RecordAsync(Guid workspaceId, Guid warehouseId, Guid productId, decimal quantity,
    14	        string idempotencyKey, DateTimeOffset fulfilledAtUtc, CancellationToken cancellationToken)
    15	    {
    16	        quantity = InventoryMovement.ValidateQuantity(quantity);
    17	        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
    18	        var strategy = dbContext.Database.CreateExecutionStrategy();
    19	        return await strategy.ExecuteAsync(async () =>
    20	        {
    21	            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
    22	            var existing = await dbContext.SalesFulfillments.SingleOrDefaultAsync(fulfillment => fulfillment.WorkspaceId == workspaceId &&
    23	                fulfillment.IdempotencyKey == idempotencyKey, cancellationToken);
    24	            if (existing is not null)
    25	            {
    26	                await transaction.CommitAsync(cancellationToken);
    27	                return existing;
    28	            }
    29	
    30	            var fulfillmentId = Guid.NewGuid();
    31	            var movement = await new InventoryLedgerWriter(dbContext).RecordAsync(workspaceId, warehouseId, productId,
    32	                InventoryMovementType.Issue, quantity, fulfillmentId.ToString("N"), fulfilledAtUtc, Guid.NewGuid(), cancellationToken);
    33	            if (movement is null)
    34	            {
    35	                await transaction.RollbackAsync(cancellationToken);
    36	                return null;
    37	            }
    38	
    39	            var fulfillment = new SalesFulfillment(fulfillmentId, workspaceId, warehouseId, productId, quantity, idempotencyKey,
    40	                movement.Id, fulfilledAtUtc);
    41	            dbContext.SalesFulfillments.Add(fulfillment);
    42	            await dbContext.SaveChangesAsync(cancellationToken);
    43	            await transaction.CommitAsync(cancellationToken);
    44	            return fulfillment;
    45	        });
    46	    }
    47	
    48	    public async Task<IReadOnlyList<SalesFulfillment>> ListAsync(Guid workspaceId, CancellationToken cancellationToken) =>
    49	        await dbContext.SalesFulfillments.AsNoTracking().Where(fulfillment => fulfillment.WorkspaceId == workspaceId)
    50	            .OrderByDescending(fulfillment => fulfillment.FulfilledAtUtc).ThenByDescending(fulfillment => fulfillment.Id)
    51	            .ToListAsync(cancellationToken);
    52	}
